import uuidimport datetimefrom typing import Optionalfrom sqlalchemy import TIMESTAMP, TEXT, VARCHAR, INTEGER, UUIDfrom sqlalchemy.orm import Mapped, mapped_columnfrom database.entity.BaseModel import BaseModelclass PlatformCeleryTaskLogModel(BaseModel):    __tablename__ = 'platform_celery_task_log'    id: Mapped[int] = mapped_column(INTEGER, autoincrement=True, primary_key=True)    task_id: Mapped[uuid.UUID] = mapped_column(UUID)    status: Mapped[Optional[str]] = mapped_column(VARCHAR(50))    task_name: Mapped[Optional[str]] = mapped_column(VARCHAR(128))    create_at: Mapped[Optional[datetime.datetime]] = mapped_column(TIMESTAMP)    desc: Mapped[Optional[str]] = mapped_column(TEXT)